/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Features:
 * - Template rendering per notification type (HTML + plain text)
 * - Recipient email validation
 * - Pluggable transport layer (inject real SMTP/SES/SendGrid for production)
 *
 * Architecture constraint: All adapters must implement NotificationAdapter
 * and be registered with NotificationService via registerAdapter().
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Default sender address */
  from: string;
  /** Optional reply-to address */
  replyTo?: string;
  /** Maximum recipient address length */
  maxRecipientLength?: number;
}

/**
 * Rendered email content ready for transport.
 */
export interface RenderedEmail {
  from: string;
  replyTo?: string;
  to: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport interface for sending emails.
 * Implement this with your email provider (SMTP, SendGrid, SES, etc.)
 */
export interface EmailTransport {
  send(email: RenderedEmail): Promise<{ messageId: string }>;
}

/**
 * In-memory transport that captures sent emails. Useful for testing and development.
 */
export class InMemoryEmailTransport implements EmailTransport {
  private sent: RenderedEmail[] = [];

  async send(email: RenderedEmail): Promise<{ messageId: string }> {
    this.sent.push(email);
    return { messageId: `msg-${this.sent.length}` };
  }

  getSentEmails(): RenderedEmail[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that a string looks like an email address.
 */
export function isValidEmail(email: string): boolean {
  if (!email || email.length > 254) return false;
  return EMAIL_REGEX.test(email);
}

/**
 * Templates keyed by notification type.
 * Each returns { subject, html, text } given the notification payload.
 */
const EMAIL_TEMPLATES: Record<
  NotificationType,
  (payload: NotificationPayload) => { subject: string; html: string; text: string }
> = {
  order_confirmation: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2563eb;">Order Confirmation</h1>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      payload.metadata?.orderId
        ? `<p style="color: #6b7280; font-size: 0.875rem;">Order ID: ${escapeHtml(String(payload.metadata.orderId))}</p>`
        : '',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #9ca3af; font-size: 0.75rem;">TaskFlow Pro — Thank you for your order!</p>',
      '</div>',
    ].join('\n'),
    text: `Order Confirmation\n\n${payload.body}\n\n--\nTaskFlow Pro`,
  }),

  order_status_update: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2563eb;">Order Status Update</h1>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #9ca3af; font-size: 0.75rem;">TaskFlow Pro — Order Updates</p>',
      '</div>',
    ].join('\n'),
    text: `Order Status Update\n\n${payload.body}\n\n--\nTaskFlow Pro`,
  }),

  welcome: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2563eb;">Welcome to TaskFlow Pro!</h1>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      '<p>Get started by exploring your dashboard.</p>',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #9ca3af; font-size: 0.75rem;">TaskFlow Pro — Welcome aboard!</p>',
      '</div>',
    ].join('\n'),
    text: `Welcome to TaskFlow Pro!\n\n${payload.body}\n\nGet started by exploring your dashboard.\n\n--\nTaskFlow Pro`,
  }),

  account_updated: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2563eb;">Account Updated</h1>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #9ca3af; font-size: 0.75rem;">TaskFlow Pro — Account Notifications</p>',
      '</div>',
    ].join('\n'),
    text: `Account Updated\n\n${payload.body}\n\n--\nTaskFlow Pro`,
  }),
};

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private config: EmailConfig;

  constructor(config: EmailConfig, transport?: EmailTransport) {
    this.config = config;
    this.transport = transport ?? new InMemoryEmailTransport();
  }

  /**
   * Render a notification payload into a full email using the template for its type.
   */
  renderTemplate(payload: NotificationPayload): RenderedEmail {
    const template = EMAIL_TEMPLATES[payload.type];
    const rendered = template(payload);

    return {
      from: this.config.from,
      replyTo: this.config.replyTo,
      to: payload.recipient,
      subject: rendered.subject,
      html: rendered.html,
      text: rendered.text,
    };
  }

  /**
   * Validate and resolve the recipient email address.
   * Returns the validated email or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    const trimmed = recipient.trim().toLowerCase();
    const maxLen = this.config.maxRecipientLength ?? 254;

    if (!trimmed) {
      throw new Error('Email recipient cannot be empty');
    }

    if (trimmed.length > maxLen) {
      throw new Error(`Email recipient exceeds maximum length of ${maxLen}`);
    }

    if (!isValidEmail(trimmed)) {
      throw new Error(`Invalid email address: ${trimmed}`);
    }

    return trimmed;
  }

  /**
   * Send a notification via email.
   *
   * 1. Validates the recipient address
   * 2. Renders the email template
   * 3. Sends via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const resolvedRecipient = this.resolveRecipient(payload.recipient);
      const resolvedPayload = { ...payload, recipient: resolvedRecipient };

      const email = this.renderTemplate(resolvedPayload);

      this.logger.info(
        `Sending email to ${email.to}: "${email.subject}"`,
      );

      await this.transport.send(email);

      this.logger.info(`Email delivered to ${email.to}`);

      return {
        notificationId: payload.id,
        channel: 'email',
        success: true,
        deliveredAt: new Date(),
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send email for ${payload.id}: ${message}`);

      return {
        notificationId: payload.id,
        channel: 'email',
        success: false,
        error: message,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all emails sent through this adapter (only works with InMemoryEmailTransport).
   */
  getSentEmails(): RenderedEmail[] {
    if (this.transport instanceof InMemoryEmailTransport) {
      return this.transport.getSentEmails();
    }
    return [];
  }

  /**
   * Clear sent emails (only works with InMemoryEmailTransport).
   */
  clearSentEmails(): void {
    if (this.transport instanceof InMemoryEmailTransport) {
      this.transport.clear();
    }
  }

  /**
   * Get the underlying transport (useful for testing).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

