import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailNotificationAdapter,
  InMemoryEmailTransport,
  isValidEmail,
} from '../../src/adapters/email.adapter.js';
import type {
  EmailConfig,
  EmailTransport,
  RenderedEmail,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

const defaultConfig: EmailConfig = {
  from: 'noreply@taskflow.test',
  replyTo: 'support@taskflow.test',
};

describe('isValidEmail', () => {
  it('should accept valid email addresses', () => {
    expect(isValidEmail('user@example.com')).toBe(true);
    expect(isValidEmail('user+tag@example.co.uk')).toBe(true);
    expect(isValidEmail('first.last@domain.org')).toBe(true);
  });

  it('should reject invalid email addresses', () => {
    expect(isValidEmail('')).toBe(false);
    expect(isValidEmail('not-an-email')).toBe(false);
    expect(isValidEmail('@domain.com')).toBe(false);
    expect(isValidEmail('user@')).toBe(false);
    expect(isValidEmail('user @example.com')).toBe(false);
    expect(isValidEmail('a'.repeat(255) + '@example.com')).toBe(false);
  });
});

describe('InMemoryEmailTransport', () => {
  let transport: InMemoryEmailTransport;

  beforeEach(() => {
    transport = new InMemoryEmailTransport();
  });

  it('should capture sent emails', async () => {
    const email: RenderedEmail = {
      from: 'noreply@test.com',
      to: 'user@test.com',
      subject: 'Test',
      html: '<p>Test</p>',
      text: 'Test',
    };

    const result = await transport.send(email);
    expect(result.messageId).toBe('msg-1');
    expect(transport.getSentEmails()).toHaveLength(1);
    expect(transport.getSentEmails()[0]?.to).toBe('user@test.com');
  });

  it('should increment message IDs', async () => {
    const email: RenderedEmail = {
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 'x',
      html: '',
      text: '',
    };

    await transport.send(email);
    const result = await transport.send(email);
    expect(result.messageId).toBe('msg-2');
  });

  it('should clear sent emails', async () => {
    const email: RenderedEmail = {
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 'x',
      html: '',
      text: '',
    };

    await transport.send(email);
    transport.clear();
    expect(transport.getSentEmails()).toHaveLength(0);
  });
});

describe('EmailNotificationAdapter', () => {
  let adapter: EmailNotificationAdapter;
  let transport: InMemoryEmailTransport;

  beforeEach(() => {
    transport = new InMemoryEmailTransport();
    adapter = new EmailNotificationAdapter(defaultConfig, transport);
  });

  describe('channel', () => {
    it('should report email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('resolveRecipient', () => {
    it('should normalize email to lowercase and trim', () => {
      expect(adapter.resolveRecipient('  Alice@Example.COM  ')).toBe('alice@example.com');
    });

    it('should throw for empty recipient', () => {
      expect(() => adapter.resolveRecipient('')).toThrow('cannot be empty');
      expect(() => adapter.resolveRecipient('   ')).toThrow('cannot be empty');
    });

    it('should throw for invalid email', () => {
      expect(() => adapter.resolveRecipient('not-an-email')).toThrow('Invalid email');
    });

    it('should throw for overly long email', () => {
      const longAdapter = new EmailNotificationAdapter(
        { ...defaultConfig, maxRecipientLength: 10 },
        transport,
      );
      expect(() => longAdapter.resolveRecipient('toolong@example.com')).toThrow(
        'exceeds maximum length',
      );
    });
  });

  describe('renderTemplate', () => {
    it('should render order_confirmation template with HTML and text', () => {
      const payload = makePayload();
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.from).toBe('noreply@taskflow.test');
      expect(rendered.replyTo).toBe('support@taskflow.test');
      expect(rendered.to).toBe('alice@example.com');
      expect(rendered.subject).toBe('Order Confirmation: order-1');
      expect(rendered.html).toContain('Order Confirmation');
      expect(rendered.html).toContain('Widget x2');
      expect(rendered.text).toContain('Widget x2');
      expect(rendered.text).toContain('TaskFlow Pro');
    });

    it('should render order_status_update template', () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Order Status Update');
      expect(rendered.text).toContain('pending to confirmed');
    });

    it('should render welcome template', () => {
      const payload = makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hi Alice, your account has been created.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Welcome to TaskFlow Pro');
      expect(rendered.html).toContain('Get started');
      expect(rendered.text).toContain('Hi Alice');
      expect(rendered.text).toContain('dashboard');
    });

    it('should render account_updated template', () => {
      const payload = makePayload({
        type: 'account_updated',
        subject: 'Account Updated',
        body: 'Your account details have been updated.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Account Updated');
      expect(rendered.text).toContain('account details');
    });

    it('should escape HTML in body content', () => {
      const payload = makePayload({
        body: 'Items: <script>alert("xss")</script>',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
    });

    it('should include orderId metadata when present', () => {
      const payload = makePayload({ metadata: { orderId: 'order-42' } });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Order ID: order-42');
    });
  });

  describe('send', () => {
    it('should send a valid notification and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const sent = transport.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.from).toBe('noreply@taskflow.test');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
    });

    it('should normalize recipient email before sending', async () => {
      const payload = makePayload({ recipient: '  ALICE@Example.COM  ' });
      await adapter.send(payload);

      const sent = transport.getSentEmails();
      expect(sent[0]?.to).toBe('alice@example.com');
    });

    it('should return failure for invalid recipient', async () => {
      const payload = makePayload({ recipient: 'not-an-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email');
      expect(transport.getSentEmails()).toHaveLength(0);
    });

    it('should return failure for empty recipient', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('cannot be empty');
    });

    it('should return failure when transport throws', async () => {
      const failingTransport: EmailTransport = {
        send: async () => {
          throw new Error('SMTP connection refused');
        },
      };
      const failAdapter = new EmailNotificationAdapter(defaultConfig, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should render the correct template for each notification type', async () => {
      await adapter.send(makePayload({ type: 'welcome', subject: 'Welcome!' }));
      await adapter.send(makePayload({ type: 'order_status_update', subject: 'Status' }));

      const sent = transport.getSentEmails();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.html).toContain('Welcome to TaskFlow Pro');
      expect(sent[1]?.html).toContain('Order Status Update');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return sent emails from in-memory transport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return empty array when using non-InMemory transport', () => {
      const customTransport: EmailTransport = {
        send: async () => ({ messageId: 'x' }),
      };
      const customAdapter = new EmailNotificationAdapter(defaultConfig, customTransport);
      expect(customAdapter.getSentEmails()).toEqual([]);
    });
  });

  describe('getTransport', () => {
    it('should return the underlying transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });
  });
});

